import styleMain from "./Main.module.css";
import { Link } from "react-router-dom";
import React from "react";

const Main = () => {
  return (
    <div className={styleMain.about}>
      <h1 className={styleMain.h1}>
        Проект преподавателя истории не об истории
      </h1>
      <Link className={styleMain.link} to="/learning">
        Обучаться
      </Link>
      <div>
        <svg id="Слой_1" viewBox="0 0 1920 1080">
          <rect className={styleMain.cls} width="1920" height="1080" />
        </svg>
      </div>
    </div>
  );
};

export default Main;
